import React from "react";
import Navbar from "../components/Navbar";
import styled from "styled-components";
import {Link} from "react-router-dom";

const Container = styled.div`
    width: 100%;
    height: 92vh;
    background-color: #071330;
`;

const Wrapper = styled.div`
    height: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
`;


const Info = styled.h2`
    color: white;
`;

const Button = styled(Link)`
    border: none;
    background-color: white;
    padding: 10px;
    margin-left: 20px;
    text-decoration: none;
    color: black;
    border: 5px solid #7BC2BC;
    &:hover{
      cursor: pointer;
      background-color: #7BC2BC;
      color: white;
      text-decoration: none;
    }
`;

const Map = styled.div`
  justify-content: left;
`;

const LanguageContainer = styled.div`
    padding-top: 5vh;
    padding-bottom: 5vh;
`;
const LanguageBox = styled.div`
    background-color: white;
    padding: 10px;
    border: 5px solid #7BC2BC;
`;
const Language = styled.img`
    height: 40px;
    width: 40px;
`;

const Home = () => {
    return (
        <div>
            <Navbar/>
            <Container>
                <Wrapper>
                    <Info>Hi, I'm Joel Harawa, a senior at New York University studying Computer Science.</Info>
                    <Info>My main interests are web development and mobile app development.</Info>
                    <Info>Here are my Programming Languages (from strongest to weakest).</Info>
                </Wrapper>
            </Container>
        </div>
    );
}

export default Home;
